/**
 * Seed Supabase products for all preview sites.
 * Processes in batches of 10 to avoid rate limits.
 *
 * Usage: npx tsx scripts/seed-commerce-products.ts
 */

import { createClient } from '@supabase/supabase-js'
import * as fs from 'fs'
import * as path from 'path'
import { randomUUID } from 'crypto'

const ROOT = path.resolve(__dirname, '..')
const SITES_DIR = path.join(ROOT, 'sites')

// Load env from .env.local
const envPath = path.join(ROOT, 'web', '.env.local')
if (fs.existsSync(envPath)) {
  for (const line of fs.readFileSync(envPath, 'utf-8').split('\n')) {
    const m = line.match(/^\s*(\w+)=(.+)$/)
    if (m) process.env[m[1]] = m[2]
  }
}

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY

if (!supabaseUrl || !supabaseKey) {
  console.error('ERROR: Supabase credentials required')
  process.exit(1)
}

const supabase = createClient(supabaseUrl, supabaseKey, {
  auth: { persistSession: false },
})

async function main() {
  console.log('=== Seeding Products for Previews ===\n')

  const entries = fs.readdirSync(SITES_DIR, { withFileTypes: true })
  const previewSlugs = entries
    .filter(e => e.isDirectory() && e.name.startsWith('preview-'))
    .map(e => e.name)
    .sort()

  console.log(`${previewSlugs.length} previews\n`)

  let total = 0
  let inserted = 0
  let skipped = 0
  let errs = 0

  // Process in batches of 10
  const BATCH = 10
  for (let i = 0; i < previewSlugs.length; i += BATCH) {
    const batch = previewSlugs.slice(i, i + BATCH)
    const rows: any[] = []

    for (const slug of batch) {
      const contentPath = path.join(SITES_DIR, slug, 'content', 'es.json')
      const sitePath = path.join(SITES_DIR, slug, 'site.json')
      if (!fs.existsSync(contentPath) || !fs.existsSync(sitePath)) {
        skipped++
        continue
      }

      const content = JSON.parse(fs.readFileSync(contentPath, 'utf-8'))
      const site = JSON.parse(fs.readFileSync(sitePath, 'utf-8'))
      const products = content.home?.products?.items
      if (!products) {
        skipped++
        continue
      }

      // First ensure business exists
      const bizType = site.businessType || 'peluqueria'
      const phone = site.contact?.phone || ''

      const bizRow = {
        slug,
        name: content.placeholders?.businessName || slug,
        type: bizType,
        vertical: site.vertical || 'beauty-personal-care',
        phone: phone,
        city: site.location?.city || 'Asunción',
        country: 'PY',
        features: site.features || {},
      }

      const { data: biz, error: bizErr } = await supabase
        .from('businesses')
        .upsert(bizRow, { onConflict: 'slug', ignoreDuplicates: false })
        .select('id')
        .single()

      if (bizErr) {
        console.error(`  ✗ ${slug}: ${bizErr.message.slice(0, 100)}`)
        errs++
        continue
      }

      // Create product rows
      for (const p of products) {
        const productSlug = p.slug || p.name.toLowerCase()
          .replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '') + '-' + slug.slice(0, 8)

        rows.push({
          id: p.id || randomUUID(),
          slug: productSlug,
          business_id: biz.id,
          name: p.name,
          description: p.description || '',
          price_cents: p.priceCents || 50000,
          category: p.category || 'General',
          tags: p.tags || [],
          image_url: p.imageUrl || null,
          status: 'active',
          inventory_policy: 'continue',
        })
        total++
      }
    }

    // Batch upsert
    if (rows.length > 0) {
      const { error } = await supabase.from('products').upsert(rows, {
        onConflict: 'slug,business_id',
        ignoreDuplicates: false,
      })
      if (error) {
        console.error(`  ✗ Batch ${i}: ${error.message.slice(0, 120)}`)
        errs += rows.length
      } else {
        inserted += rows.length
      }
    }

    const pct = Math.round((i + BATCH) / previewSlugs.length * 100)
    console.log(`  ${Math.min(i + BATCH, previewSlugs.length)}/${previewSlugs.length} (${pct}%) — ${inserted} products seeded`)
  }

  console.log(`\n=== Results ===`)
  console.log(`Products created: ${inserted}`)
  console.log(`Errors: ${errs}`)
  console.log(`Total processed: ${total}`)
}

main().catch(err => { console.error('Fatal:', err); process.exit(1) })
